const animalBehaviors = {
  eat() { console.log('Eating...'); },
  sleep() { console.log('Sleeping...'); }
};

// Create specific animals that link to the shared behaviors
const dog = Object.create(animalBehaviors);
dog.bark = () => console.log('Woof!');

const cat = Object.create(animalBehaviors);
cat.meow = () => console.log('Meow!');

// dog delegates 'eat' to animalBehaviors
dog.eat(); 
// cat delegates 'sleep' to animalBehaviors
cat.sleep();
